import{_ as e,a as t,b as i,c as o}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as n,o as l,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Backup ridondante e cambio sorgente di lettura","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/Other/redundant-backup-and-read-source.md","filePath":"it-IT/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),c={name:"it-IT/Other/redundant-backup-and-read-source.md"};function p(u,a,s,b,k,h){return l(),d("div",null,[...a[0]||(a[0]=[r('<h1 id="backup-ridondante-e-cambio-sorgente-di-lettura" tabindex="-1">Backup ridondante e cambio sorgente di lettura <a class="header-anchor" href="#backup-ridondante-e-cambio-sorgente-di-lettura" aria-label="Permalink to &quot;Backup ridondante e cambio sorgente di lettura&quot;">​</a></h1><p>Il backup ridondante salva una copia extra di un file già caricato.</p><p>Sia il file principale sia il file di backup possono essere usati come sorgente di lettura. Per i visitatori normalmente non cambia nulla: cambia solo il canale storage che serve il file.</p><h2 id="cosa-puo-fare-il-backup-ridondante" tabindex="-1">Cosa può fare il backup ridondante <a class="header-anchor" href="#cosa-puo-fare-il-backup-ridondante" aria-label="Permalink to &quot;Cosa può fare il backup ridondante&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funzione</th><th>Descrizione</th></tr></thead><tbody><tr><td>Salvare una copia extra</td><td>Esegue backup su un altro canale di upload per ridurre il rischio di guasto di un singolo canale.</td></tr><tr><td>Cambiare sorgente di lettura</td><td>Dopo un backup riuscito, passa la lettura tra canale principale e canale di backup.</td></tr><tr><td>Backup singolo file</td><td>Esegue backup da pagina dettaglio file.</td></tr><tr><td>Backup in blocco</td><td>Seleziona più file nel pannello admin e salvali insieme.</td></tr><tr><td>Backup ridondante globale</td><td>Esegue backup per cartella da Altre impostazioni.</td></tr></tbody></table><h2 id="voce-backup-ridondante" tabindex="-1">Voce Backup ridondante <a class="header-anchor" href="#voce-backup-ridondante" aria-label="Permalink to &quot;Voce Backup ridondante&quot;">​</a></h2><p>Apri:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+e+'" alt="Backup ridondante" loading="lazy"></p><p>Questa voce è comoda per aggiungere backup a una cartella o a tutti i file in blocco.</p><p>Puoi selezionare manualmente il canale di backup oppure scegliere il cambio automatico e lasciare che ImgBed trovi un canale adatto.</p><h2 id="backup-dal-dettaglio-file" tabindex="-1">Backup dal dettaglio file <a class="header-anchor" href="#backup-dal-dettaglio-file" aria-label="Permalink to &quot;Backup dal dettaglio file&quot;">​</a></h2><p>Apri la pagina dettaglio di un file nel pannello admin e clicca backup.</p><p><img src="'+t+'" alt="Backup nel dettaglio file" loading="lazy"></p><p>È il modo più pratico per salvare subito una copia di un file importante.</p><p>Dopo un backup riuscito, la pagina dettaglio mostra le sorgenti di lettura disponibili.</p><h2 id="backup-in-blocco-da-selezione" tabindex="-1">Backup in blocco da selezione <a class="header-anchor" href="#backup-in-blocco-da-selezione" aria-label="Permalink to &quot;Backup in blocco da selezione&quot;">​</a></h2><p>Nel pannello admin seleziona più file ed esegui il backup in blocco.</p><p><img src="'+i+'" alt="Backup in blocco" loading="lazy"></p><p>È indicato per un gruppo di file.</p><p>Backup da selezione, backup da dettaglio file e backup ridondante in Altre impostazioni usano lo stesso sistema. Sono solo punti di ingresso diversi.</p><h2 id="cambiare-sorgente-di-lettura-dopo-il-backup" tabindex="-1">Cambiare sorgente di lettura dopo il backup <a class="header-anchor" href="#cambiare-sorgente-di-lettura-dopo-il-backup" aria-label="Permalink to &quot;Cambiare sorgente di lettura dopo il backup&quot;">​</a></h2><p>Dopo il backup, la pagina dettaglio permette di cambiare sorgente di lettura:</p><table tabindex="0"><thead><tr><th>Sorgente lettura</th><th>Descrizione</th></tr></thead><tbody><tr><td>Canale principale</td><td>Legge dal canale usato per il primo upload.</td></tr><tr><td>Canale di backup</td><td>Legge dal canale in cui è salvata la copia ridondante.</td></tr></tbody></table><p><img src="'+o+'" alt="Cambia sorgente lettura dopo backup" loading="lazy"></p><p>I visitatori non devono sapere se il file arriva dal canale principale o dal backup.</p><p>La sorgente scelta diventa quella preferita per gli accessi successivi.</p><h2 id="quando-il-backup-viene-saltato" tabindex="-1">Quando il backup viene saltato <a class="header-anchor" href="#quando-il-backup-viene-saltato" aria-label="Permalink to &quot;Quando il backup viene saltato&quot;">​</a></h2><p>Questi casi vengono saltati durante il backup. Non sono errori.</p><table tabindex="0"><thead><tr><th>Caso</th><th>Perché viene saltato</th></tr></thead><tbody><tr><td>Già con backup</td><td>Un file già salvato in backup non viene copiato di nuovo.</td></tr><tr><td>Canale principale e backup uguali</td><td>Il backup deve stare su un altro canale per avere senso.</td></tr><tr><td>Nessun canale di backup utilizzabile</td><td>Non è disponibile un canale alternativo adatto.</td></tr></tbody></table><p>In breve: i backup devono finire su un altro canale, e i file già copiati non consumano nuovo spazio.</p><h2 id="canale-principale-e-canale-di-backup" tabindex="-1">Canale principale e canale di backup <a class="header-anchor" href="#canale-principale-e-canale-di-backup" aria-label="Permalink to &quot;Canale principale e canale di backup&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Nome</th><th>Significato</th></tr></thead><tbody><tr><td>Canale principale</td><td>Canale usato al primo upload del file.</td></tr><tr><td>Canale di backup</td><td>Canale che conserva la copia ridondante.</td></tr><tr><td>Sorgente principale</td><td>Il file viene letto dal canale principale.</td></tr><tr><td>Sorgente backup</td><td>Il file viene letto dal canale di backup.</td></tr></tbody></table><p>Le due sorgenti hanno lo stesso comportamento per l&#39;utente.</p><p>Finché il file di backup è disponibile, immagini, video e link download continuano a funzionare dopo il passaggio alla sorgente di backup.</p><h2 id="cosa-succede-quando-un-file-viene-eliminato" tabindex="-1">Cosa succede quando un file viene eliminato <a class="header-anchor" href="#cosa-succede-quando-un-file-viene-eliminato" aria-label="Permalink to &quot;Cosa succede quando un file viene eliminato&quot;">​</a></h2><p>Quando elimini un file, ImgBed elimina sia il file principale sia il file di backup.</p>',37)])])}const v=n(c,[["render",p]]);export{f as __pageData,v as default};
